/**
 * Resource Audit Log table - Change history tracking
 *
 * Maintains a complete audit trail of all resource modifications for compliance,
 * debugging, and analytics. Preserves history even after resource deletion.
 *
 * @property {number} id - Auto-incrementing primary key
 * @property {number} resourceId - Current resource reference (nullable, SET NULL on resource delete)
 * @property {number} originalResourceId - Original resource ID, never nullified (preserves history after deletion)
 * @property {string} action - Action type: 'created', 'updated', 'approved', 'rejected', 'synced', 'deleted' (required)
 * @property {string} performedBy - User who performed the action (nullable, SET NULL on user delete)
 * @property {object} changes - JSON object containing changed fields and values
 * @property {string} notes - Optional notes or comments about the change
 * @property {timestamp} createdAt - When the action occurred
 *
 * Constraints:
 * - resourceId uses SET NULL on delete (maintains audit log after resource deletion)
 * - performedBy uses SET NULL on delete (maintains audit log after user deletion)
 * - originalResourceId never changes (preserves original resource ID for historical reference)
 *
 * Relationships:
 * - References resources.id (many-to-one, nullable)
 * - References users.id for performedBy (many-to-one, nullable)
 */
export const resourceAuditLog = pgTable("resource_audit_log", {
  id: serial("id").primaryKey(),
  resourceId: integer("resource_id").references(() => resources.id, { onDelete: "set null" }),
  originalResourceId: integer("original_resource_id"), // Never SET NULL - preserves history after deletion
  action: text("action").notNull(), // created, updated, approved, rejected, synced, deleted
  performedBy: varchar("performed_by").references(() => users.id, { onDelete: "set null" }),
  changes: jsonb("changes").$type<Record<string, any>>(),
  notes: text("notes"),
  createdAt: timestamp("created_at").defaultNow(),
});

