/**
 * Enrichment Queue table - Individual resource enrichment tasks
 *
 * Tracks individual resource enrichment tasks within a batch job.
 * Each queue item represents one resource to be analyzed by Claude AI with retry logic.
 *
 * @property {number} id - Auto-incrementing primary key
 * @property {number} jobId - Parent enrichment job (required, cascades on delete)
 * @property {number} resourceId - Resource to enrich (required, cascades on delete)
 * @property {string} status - Task status: 'pending', 'processing', 'completed', 'failed', 'skipped' (default: 'pending')
 * @property {number} retryCount - Number of retry attempts made (default: 0)
 * @property {number} maxRetries - Maximum retry attempts allowed (default: 3)
 * @property {string} errorMessage - Error details if enrichment failed
 * @property {object} aiMetadata - Claude AI-generated metadata (suggested title, description, tags, category, subcategory, confidence, key topics)
 * @property {timestamp} processedAt - When enrichment completed or failed
 * @property {timestamp} createdAt - Queue item creation timestamp
 * @property {timestamp} updatedAt - Last status update timestamp
 *
 * Constraints:
 * - Cascades delete when parent job or resource is deleted
 *
 * Indexes:
 * - idx_enrichment_queue_job_id: Fast lookup of all tasks in a job
 * - idx_enrichment_queue_resource_id: Check enrichment status for a resource
 * - idx_enrichment_queue_status: Fast filtering by task status
 *
 * Relationships:
 * - References enrichmentJobs.id (many-to-one)
 * - References resources.id (many-to-one)
 */
export const enrichmentQueue = pgTable(
  "enrichment_queue",
  {
    id: serial("id").primaryKey(),
    jobId: integer("job_id").references(() => enrichmentJobs.id, { onDelete: "cascade" }).notNull(),
    resourceId: integer("resource_id").references(() => resources.id, { onDelete: "cascade" }).notNull(),
    status: text("status").notNull().default("pending"), // pending, processing, completed, failed, skipped
    retryCount: integer("retry_count").default(0),
    maxRetries: integer("max_retries").default(3),
    errorMessage: text("error_message"),
    aiMetadata: jsonb("ai_metadata").$type<{
      suggestedTitle?: string;
      suggestedDescription?: string;
      suggestedTags?: string[];
      suggestedCategory?: string;
      suggestedSubcategory?: string;
      confidence?: number;
      keyTopics?: string[];
    }>(),
    processedAt: timestamp("processed_at"),
    createdAt: timestamp("created_at").defaultNow(),
    updatedAt: timestamp("updated_at").defaultNow(),
  },
  (table) => [
    index("idx_enrichment_queue_job_id").on(table.jobId),
    index("idx_enrichment_queue_resource_id").on(table.resourceId),
    index("idx_enrichment_queue_status").on(table.status),
  ]
);

export const insertEnrichmentQueueSchema = createInsertSchema(enrichmentQueue).pick({
  jobId: true,
  resourceId: true,
  status: true,
  retryCount: true,
  maxRetries: true,
});

